18115 bool SLPVectorizerPass::vectorizeHorReduction(
18116     PHINode *P, Instruction *Root, BasicBlock *BB, BoUpSLP &R, TargetTransformInfo *TTI,
18117     SmallVectorImpl<WeakTrackingVH> &PostponedInsts) {
18118   if (!ShouldVectorizeHor)
18119     return false;
18120   bool TryOperandsAsNewSeeds = P && isa<BinaryOperator>(Root);
18121 
18122   if (Root->getParent() != BB || isa<PHINode>(Root))
18123     return false;
18124 
18125   // If we can find a secondary reduction root, use that instead.
18126   auto SelectRoot = [&]() {
18127     if (TryOperandsAsNewSeeds && isReductionCandidate(Root) &&
18128         HorizontalReduction::getRdxKind(Root) != RecurKind::None)
18129       if (Instruction *NewRoot = tryGetSecondaryReductionRoot(P, Root))
18130         return NewRoot;
18131     return Root;
18132   };
18133 
18134   // Start analysis starting from Root instruction. If horizontal reduction is
18135   // found, try to vectorize it. If it is not a horizontal reduction or
18136   // vectorization is not possible or not effective, and currently analyzed
18137   // instruction is a binary operation, try to vectorize the operands, using
18138   // pre-order DFS traversal order. If the operands were not vectorized, repeat
18139   // the same procedure considering each operand as a possible root of the
18140   // horizontal reduction.
18141   // Interrupt the process if the Root instruction itself was vectorized or all
18142   // sub-trees not higher that RecursionMaxDepth were analyzed/vectorized.
18143   // If a horizintal reduction was not matched or vectorized we collect
18144   // instructions for possible later attempts for vectorization.
18145   std::queue<std::pair<Instruction *, unsigned>> Stack;
18146   Stack.emplace(SelectRoot(), 0);
18147   SmallPtrSet<Value *, 8> VisitedInstrs;
18148   bool Res = false;
18149   auto &&TryToReduce = [this, TTI, &R](Instruction *Inst) -> Value * {
18150     if (R.isAnalyzedReductionRoot(Inst))
18151       return nullptr;
18152     if (!isReductionCandidate(Inst))
18153       return nullptr;
18154     HorizontalReduction HorRdx;
18155     if (!HorRdx.matchAssociativeReduction(R, Inst, *SE, *DL, *TLI))
18156       return nullptr;
18157     return HorRdx.tryToReduce(R, *DL, TTI, *TLI);
18158   };
18159   auto TryAppendToPostponedInsts = [&](Instruction *FutureSeed) {
18160     if (TryOperandsAsNewSeeds && FutureSeed == Root) {
18161       FutureSeed = getNonPhiOperand(Root, P);
18162       if (!FutureSeed)
18163         return false;
18164     }
18165     // Do not collect CmpInst or InsertElementInst/InsertValueInst as their
18166     // analysis is done separately.
18167     if (!isa<CmpInst, InsertElementInst, InsertValueInst>(FutureSeed))
18168       PostponedInsts.push_back(FutureSeed);
18169     return true;
18170   };
18171 
18172   while (!Stack.empty()) {
18173     Instruction *Inst;
18174     unsigned Level;
18175     std::tie(Inst, Level) = Stack.front();
18176     Stack.pop();
18177     // Do not try to analyze instruction that has already been vectorized.
18178     // This may happen when we vectorize instruction operands on a previous
18179     // iteration while stack was populated before that happened.
18180     if (R.isDeleted(Inst))
18181       continue;
18182     if (Value *VectorizedV = TryToReduce(Inst)) {
18183       Res = true;
18184       if (auto *I = dyn_cast<Instruction>(VectorizedV)) {
18185         // Try to find another reduction.
18186         Stack.emplace(I, Level);
18187         continue;
18188       }
18189       if (R.isDeleted(Inst))
18190         continue;
18191     } else {
18192       // We could not vectorize `Inst` so try to use it as a future seed.
18193       if (!TryAppendToPostponedInsts(Inst)) {
18194         assert(Stack.empty() && "Expected empty stack");
18195         break;
18196       }
18197     }
18198 
18199     // Try to vectorize operands.
18200     // Continue analysis for the instruction from the same basic block only to
18201     // save compile time.
18202     if (++Level < RecursionMaxDepth)
18203       for (auto *Op : Inst->operand_values())
18204         if (VisitedInstrs.insert(Op).second)
18205           if (auto *I = dyn_cast<Instruction>(Op))
18206             // Do not try to vectorize CmpInst operands,  this is done
18207             // separately.
18208             if (!isa<PHINode, CmpInst, InsertElementInst, InsertValueInst>(I) &&
18209                 !R.isDeleted(I) && I->getParent() == BB)
18210               Stack.emplace(I, Level);
18211   }
18212   return Res;
18213 }
